typedef struct {
    float weight;
    long assign;
    float cost;
} Point_Struct;

__kernel void dummy_kernel(__global int *out) {
    size_t gid = get_global_id(0);
    if (out && gid == 0) out[0] = 0;
}

__kernel void pgain_kernel(__global const Point_Struct *p,
                           __global const float *coord,
                           __global float *work_mem,
                           __global const int *center_table,
                           __global char *switch_membership,
                           __local float *x_coord,
                           const int num,
                           const int dim,
                           const long x,
                           const int K) {
    const int gid = (int)get_global_id(0);
    const int lid = (int)get_local_id(0);
    const int lsize = (int)get_local_size(0);

    for (int d = lid; d < dim; d += lsize) {
        x_coord[d] = coord[d * num + (int)x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (gid >= num) return;

    float result = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + gid] - x_coord[d];
        result += diff * diff;
    }

    const float x_cost = result * p[gid].weight;
    const float current_cost = p[gid].cost;
    const int row = gid * (K + 1);

    if (x_cost < current_cost) {
        switch_membership[gid] = (char)'1';
        work_mem[row + K] = x_cost - current_cost;
    } else {
        const long assign = p[gid].assign;
        const int cidx = center_table[(int)assign];
        work_mem[row + cidx] = current_cost - x_cost;
    }
}
